head.script:
/**
 * 화 면 명 : 사업소관리
 * 메뉴경로 : 엔콜/기초자료/지사>사업소관리
 * ASIS경로 : /dongwon-ntis-engine/src/main/webapp/bp/fbp/bi/bi/ez_101_01_01b.jsp
 * 작 성 자 : 유청아
 * 작 업 일 : 2026-03-16
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항

 * 수정이력 :
 *    - 2026-03-16      유청아    최초작성
 *    - 2026-04-10      이진우    T-5788 조치완료(저장오류 조치완료)
 */
// 직원소속관리 버튼 삭제(2018년 이후로 호출없음,ez_104_01_01p 프로그램 삭제)

scwin.UserID = $c.data.getMemInfo("userId");;  //사용자ID
scwin.UserName = $c.data.getMemInfo("UserName");;  //사용자명

console.log("UserID::", scwin.UserID);
console.log("UserName::", scwin.UserName);

scwin.BANK_IU_FLAG = false; //tobe 추가됨
scwin.BRANCH_IU_FLAG = false; //tobe 추가됨

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.setCombo();

};

scwin.Input_Check = function (Flag) {
    switch (Flag) {
        case 'RegisterAccount':  //계좌 등록	  					
            if (ds_Branch.getRowPosition < 0) {
                $c.win.alert("지사/사업소 정보를 추가 후 계좌정보를 등록해주세요");
                return false;
            }

            if ($c.str.trim(ed_bankAcntNo.getValue()) == "") {
                $c.win.alert("계좌번호를 입력하세요");
                ed_bankAcntNo.focus();
                return false;
            }
            return true;

        case 'SaveBranch':   //영업점 등록	  	  					
            if ($c.str.trim(ed_ofcNm.getValue()) == "") {
                $c.win.alert("상호를 입력하세요");
                ed_ofcNm.focus();
                return false;
            }
            if ($c.str.trim(ed_crnNo.getValue()) == "") {
                $c.win.alert("사업자 번호를 입력하세요");
                ed_crnNo.focus();
                return false;
            }
            if ($c.str.trim(ed_picNm.getValue()) == "") {
                $c.win.alert("대표자명을 입력하세요");
                ed_picNm.focus();
                return false;
            }
            if (acb_prefDistrict1.getValue() == "" || acb_prefDistrict2.getValue() == "") {
                $c.win.alert("선호권역은 임의로 입력할 수 없습니다.");
                return false;
            }
            if (!$c.data.fn_isBusiNoByValue($c.str.trim(ed_crnNo.getValue()))) {
                $c.win.alert("잘못된 사업자 번호입니다.");
                ed_crnNo.focus();
                return false;
            }
            return true;

        default:
            break;
    }
}

//-------------------------------------------------------------------------
// 콤보박스 셋팅
//-------------------------------------------------------------------------
scwin.setCombo = async function () {
    ds_BranchOfcNm.setJSON([]);
    await $c.sbm.execute(sbm_getBranchOfcNm);

    ds_prefDistrict.setJSON([]);
    await $c.sbm.execute(sbm_getPrefDistrict);

    ds_prefDistrict2.setJSON([]);
    ds_prefDistrict2.setJSON(ds_prefDistrict.getAllJSON());

    scwin.RetriveBranch();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.RetriveBranch = function () {
    if (acb_STYPE.getValue() == 0) { //조회조건이 하나도 없다			
        dma_search.set("stype", acb_STYPE.getValue());
        dma_search.set("stext", "");

        ds_Branch.setJSON([]);
        $c.sbm.execute(sbm_reterieve);
    } else {
        if ($c.str.trim(ed_STEXT.getValue()) != "") {
            dma_search.set("stype", acb_STYPE.getValue());
            dma_search.set("stext", ed_STEXT.getValue());
        } else {
            $c.win.alert("조회조건이 입력되지 않았습니다.");
            return;
        }

        ds_Branch.setJSON([]);
        $c.sbm.execute(sbm_reterieve);
    }
};

//-------------------------------------------------------------------------
// 등록(계좌)
//-------------------------------------------------------------------------
scwin.RegisterAccount = async function () {
    if (!scwin.Input_Check("RegisterAccount")) return;

    ds_result.setJSON([]);
    ds_SaveBankInfo.setJSON([]);
    ds_SaveBankInfo.insertRow();
    //ds_SaveBankInfo.setCellData(0, "bankCd") = bankCdVal_combo.ValueOfIndex("code", bankCdVal_combo.Index);
    ds_SaveBankInfo.setCellData(0, "bankCd", dma_Branch.get("bankCd"));
    ds_SaveBankInfo.setCellData(0, "bankAcntNo", ed_bankAcntNo.getValue());
    ds_SaveBankInfo.setCellData(0, "dpstr", ed_dpstr.getValue());
    ds_SaveBankInfo.setCellData(0, "rmk", ed_accountRmk.getValue());
    ds_SaveBankInfo.setCellData(0, "ez106Idx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "ez106Idx"));

    if (scwin.BANK_IU_FLAG.checked)
        ds_SaveBankInfo.setCellData(ds_SaveBankInfo.getRowPosition(), "ez114Idx", 0);  //신규등록	
    else
        ds_SaveBankInfo.setCellData(ds_SaveBankInfo.getRowPosition(), "ez114Idx", ds_BankList.getCellData(ds_BankList.getRowPosition(), "ez114Idx")); //업데이트

    let result = await $c.sbm.execute(sbm_SaveBankInfo);

    if (ds_result.getCellData(0, "outMsg") == "1.0")
        if (scwin.BANK_IU_FLAG) {
            await $c.win.alert("계좌 등록 완료");
            scwin.BANK_IU_FLAG = false;
        } else {
            await $c.win.alert("계좌 수정 완료");
        }
    else
        await $c.win.alert("계좌 등록 실패");

    scwin.RetrieveAccount();
};

//-------------------------------------------------------------------------
// 삭제(계좌)
//-------------------------------------------------------------------------
scwin.DeleteBankInfo = async function () {
    if (ds_BankList.getRowPosition() < 0) return;
    let ret = await $c.win.confirm("선택하신 계좌정보를 삭제 하시겠습니까?");
    if (ret == 0) return;

    ds_result.setJSON([]);
    ds_DeleteBankInfo.setJSON([]);
    ds_DeleteBankInfo.insertRow();
    ds_DeleteBankInfo.setCellData(0, "userId", scwin.UserID);
    ds_DeleteBankInfo.setCellData(0, "ez114Idx", ds_BankList.getCellData(ds_BankList.getRowPosition(), "ez114Idx"));

    let result = await $c.sbm.execute(sbm_DeleteBankInfo);

    if (result.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_result.getCellData(0, "outMsg") == "1.0")
        $c.win.alert("삭제완료");
    else
        $c.win.alert("삭제실패");

    ed_bankAcntNo.setValue("");
    ed_dpstr.setValue("");
    ed_accountRmk.setValue("");

    scwin.RetrieveAccount();
};

//-------------------------------------------------------------------------
// 신규(계좌)
//-------------------------------------------------------------------------
scwin.addAccount = function () {
    scwin.BANK_IU_FLAG = true;

    ed_bankAcntNo.setValue("");
    ed_dpstr.setValue("");
    ed_accountRmk.setValue("");
    //?????????????????????
    //bankCdVal_combo.Index = 0;
    dma_Branch.set("bankCd", "");
};

//-------------------------------------------------------------------------
// 계좌정보 목록 조회
//-------------------------------------------------------------------------
scwin.RetrieveAccount = function () {
    if (ds_Branch.getRowPosition() < 0) return;

    ds_BankList.setJSON([]);
    dma_condBankList.set("ez106Idx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "ez106Idx"));

    $c.sbm.execute(sbm_reterieveBankList);
};

//-------------------------------------------------------------------------
// 신규등록 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_ClearData = function () {
    ed_ofcNm.setValue("");
    ed_telNo.setValue("");
    ed_faxNo.setValue("");
    ed_crnNo.setValue(""); //사업자번호
    ed_picNm.setValue(""); //대표자명    
    ed_handphoneNo.setValue(""); //휴대전화
    ed_picSsn.setValue("");      //주민등록번호
    ed_bizcond.setValue("");
    ed_catBusi.setValue("");
    ed_rmk.setValue("");
    udc_coDtlAddr.setValue(""); //주소 UDC
    ed_coZipcode.setValue(""); //우편번호
    udc_dtlAddr.setValue(""); //DM주소 UDC
    ed_zipcode.setValue(""); //DM우편번호
    cbx_taxinvcYn.setValue("");

    acb_prefDistrict1.options.chooseOption = true;
    acb_prefDistrict1.refreshItemset();
    acb_prefDistrict2.options.chooseOption = true;
    acb_prefDistrict2.refreshItemset();

    ed_bankAcntNo.setValue(""); //계좌번호
    ed_dpstr.setValue("");      //예금주
    ed_accountRmk.setValue(""); //비고
    scwin.BRANCH_IU_FLAG = false;

    acb_branch.setDisabled(false);

    var row = -1;
    var idx = ds_BranchOfcNm.getMatchedIndex("hdofficeIdx", acb_branch.getValue());
    if (idx.length != 0) {
        row = idx[0];
    }

    var BHOFFICE = ds_BranchOfcNm.getCellData(row, "bhofficeIdx");

    if (BHOFFICE == "0")
        rd_branch.setValue("1");
    else
        rd_branch.setValue("2");
};

//-------------------------------------------------------------------------
// 삭제하기 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_DeleteBranch = async function () {
    var conform = "선택하신  [" + ds_Branch.getCellData(ds_Branch.getRowPosition(), "ofcNm") + "] 을/를 삭제 하시겠습니까?";
    let ret = await $c.win.confirm(conform);
    if (ret == 0) return;

    // ds_DeleteBranch.setJSON([]);
    ds_DeleteBranch.removeAll(); //removeAll()은 모든 행을 삭제 상태(D)로 변경합니다. 이후 서버와 통신(Submission)하여 DB에서도 삭제하고 싶을 때 사용합니다.    
    ds_DeleteBranch.insertRow();
    ds_DeleteBranch.setCellData(0, "hdofficeIdx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "hdofficeIdx"));
    ds_DeleteBranch.setCellData(0, "bhofficeIdx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "bhofficeIdx"));
    ds_DeleteBranch.setCellData(0, "officeIdx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "officeIdx"));
    ds_DeleteBranch.setCellData(0, "ez106Idx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "ez106Idx"));
    ds_DeleteBranch.setCellData(0, "regId", scwin.UserID);

    //tobe : 서버단 호출시 sbm_SaveBranch에 설정된 out(ds_result) 데이타셋는 호출시 빈값으로 넘겨야 함
    //       데이타가 있는 상태로 넘기면 두번째 호출시 에러발생 할 수 있음
    ds_result.removeAll();

    let e = await $c.sbm.execute(sbm_DeleteBranch);

    //scwin.sbm_DeleteBranch_submitdone
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_result.getRowCount() > 0 && !$c.util.isEmpty(ds_result.getCellData(0, "outMsg")))
        $c.win.alert(ds_result.getCellData(0, "outMsg"));
        // $c.gus.cfAlertMsg(MSG_CM_INF_001);

    scwin.f_ClearData();
    scwin.RetriveBranch();

};

//-------------------------------------------------------------------------
// 저장하기 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_SaveBranch = function () {
    if (!scwin.Input_Check("SaveBranch")) return;

    // ds_SaveBranch.setJSON([]);
    ds_SaveBranch.removeAll(); //removeAll()은 모든 행을 삭제 상태(D)로 변경합니다. 이후 서버와 통신(Submission)하여 DB에서도 삭제하고 싶을 때 사용합니다.
    ds_SaveBranch.insertRow();

    // BRANCH_IU_FLAG= true : Update, BRANCH_IU_FLAG=false :Insert
    if (scwin.BRANCH_IU_FLAG) {
        ds_SaveBranch.setCellData(0, "iuFlag", "U");  //영업소 수정
        ds_SaveBranch.setCellData(0, "ihdofficeIdx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "hdofficeIdx"));
        ds_SaveBranch.setCellData(0, "ibhofficeIdx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "bhofficeIdx"));
        ds_SaveBranch.setCellData(0, "iofficeIdx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "officeIdx"));
    } else {
        ds_SaveBranch.setCellData(0, "iuFlag", "I"); //영업소 신규

        let row = -1;
        // 1. 조건에 맞는 행의 인덱스 찾기 (웹스퀘어는 0부터 시작)
        let idx = ds_BranchOfcNm.getMatchedIndex("hdofficeIdx", acb_branch.getValue());
        console.log("idx::",idx);        
        if (idx.length > 0) { // getMatchedIndex는 배열을 반환합니다.
            row = idx[0]; // 첫 번째로 찾은 행의 인덱스 (0부터 시작)
        }
        console.log("row::",row);
        if (row > -1) {
            console.log("acb_branch.getValue()::",acb_branch.getValue());
            ds_SaveBranch.setCellData(0, "ihdofficeIdx", acb_branch.getValue());
            ds_SaveBranch.setCellData(0, "ibhofficeIdx", ds_BranchOfcNm.getCellData(row, "bhofficeIdx"));
            ds_SaveBranch.setCellData(0, "iofficeIdx", ds_BranchOfcNm.getCellData(row, "officeIdx"));
        }
    }

    if (rd_branch.getValue() == "0")  //본사 지사 사업소 구분.
        ds_SaveBranch.setCellData(0, "officeTyp", "0"); //본사
    else if (rd_branch.getValue() == "1")
        ds_SaveBranch.setCellData(0, "officeTyp", "1"); //지사
    else
        ds_SaveBranch.setCellData(0, "officeTyp", "2"); //사업소

    ds_SaveBranch.setCellData(0, "ez108Idx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "ez108Idx"));
    ds_SaveBranch.setCellData(0, "ez106Idx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "ez106Idx"));
    ds_SaveBranch.setCellData(0, "ofcNm", ed_ofcNm.getValue());
    ds_SaveBranch.setCellData(0, "bizcond", ed_bizcond.getValue());
    ds_SaveBranch.setCellData(0, "catBusi", ed_catBusi.getValue());

    ds_SaveBranch.setCellData(0, "prefDistrict1", acb_prefDistrict1.getText(true));
    ds_SaveBranch.setCellData(0, "prefDistrict1Cd", acb_prefDistrict1.getValue());
    ds_SaveBranch.setCellData(0, "prefDistrict2", acb_prefDistrict2.getText(true));
    ds_SaveBranch.setCellData(0, "prefDistrict2Cd", acb_prefDistrict2.getValue());

    ds_SaveBranch.setCellData(0, "telNo", ed_telNo.getValue());
    ds_SaveBranch.setCellData(0, "faxNo", ed_faxNo.getValue());
    ds_SaveBranch.setCellData(0, "zipcode", ed_coZipcode.getValue());
    ds_SaveBranch.setCellData(0, "dtlAddr", udc_coDtlAddr.getValue());

    if (cbx_taxinvcYn.getValue() == "1")  //세금계산서여부 
        ds_SaveBranch.setCellData(0, "taxinvcYn", "Y");
    else
        ds_SaveBranch.setCellData(0, "taxinvcYn", "N");

    ds_SaveBranch.setCellData(0, "dmZipcode", ed_zipcode.getValue());
    ds_SaveBranch.setCellData(0, "regId", scwin.UserID);
    ds_SaveBranch.setCellData(0, "dmDtlAddr", udc_dtlAddr.getValue());
    ds_SaveBranch.setCellData(0, "rmk", ed_rmk.getValue());
    ds_SaveBranch.setCellData(0, "picNm", ed_picNm.getValue());
    ds_SaveBranch.setCellData(0, "handphoneNo", ed_handphoneNo.getValue().replace(/-/g, ""));
    ds_SaveBranch.setCellData(0, "picSsn", ed_picSsn.getValue());
    ds_SaveBranch.setCellData(0, "crnNo", ed_crnNo.getValue());

console.log("ds_SaveBranch::", ds_SaveBranch.getRowJSON(0));
    //tobe : 서버단 호출시 sbm_SaveBranch에 설정된 out(ds_result) 데이타셋는 호출시 빈값으로 넘겨야 함
    //       데이타가 있는 상태로 넘기면 두번째 호출시 에러발생 할 수 있음
    ds_result.removeAll();

    $c.sbm.execute(sbm_SaveBranch);
}

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_reterieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_Branch.getRowCount() == 0) {
        $c.win.alert("조회 결과가 없습니다.");
    } else {
        gr_office.setFocusedCell(0, "branch", false);
        scwin.bindBranch();
    }

    tbx_totalRows.setValue(ds_Branch.getRowCount());
};

//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_SaveBranch_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_result.getRowCount() > 0 && !$c.gus.cfIsNull(ds_result.getCellData(0, "outMsg")))
        $c.win.alert(ds_result.getCellData(0, "outMsg"));

    scwin.RetriveBranch();
};

//-------------------------------------------------------------------------
// 삭제 submitdone
//-------------------------------------------------------------------------
// scwin.sbm_DeleteBranch_submitdone = async function (e) {
//     if (e.responseJSON.resultDataSet[0].Code < 0) return;

//     if (ds_result.getRowCount() > 0 && !$c.util.isEmpty(ds_result.getCellData(0, "outMsg")))
//         $c.win.alert(ds_result.getCellData(0, "outMsg"));

//     await scwin.f_ClearData();
//     scwin.RetriveBranch();

// };

scwin.acb_branch_onviewchange = function (info) {
    var row = -1;
    var idx = ds_BranchOfcNm.getMatchedIndex("hdofficeIdx", acb_branch.getValue());
    if (idx.length != 0) {
        row = idx[0];
    }

    var BHOFFICE = ds_BranchOfcNm.getCellData(row, "bhofficeIdx");

    if (BHOFFICE == "0")
        rd_branch.setValue("1");
    else
        rd_branch.setValue("2");
};

//-------------------------------------------------------------------------
// 계좌정보 목록 그리드 클릭
//-------------------------------------------------------------------------
scwin.gr_bankacc_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.BANK_IU_FLAG = false;

    //bankCdVal_combo.Index = bankCdVal_combo.IndexOfColumn("name", ds_BankList.NameValue(rowIndex, "accountNm"));
    var row = -1;
    var idx = ds_comboBranch.getMatchedIndex("name", ds_BankList.getCellData(rowIndex, "accountNm"));

    if (idx.length != 0) {
        row = idx[0];
        dma_Branch.set("bankCd", ds_comboBranch.getCellData(row, "bnkCd"));
    }

    ed_bankAcntNo.setValue(ds_BankList.getCellData(rowIndex, "bankAcntNo"));
    ed_dpstr.setValue(ds_BankList.getCellData(rowIndex, "dpstr"));
    ed_accountRmk.setValue(ds_BankList.getCellData(rowIndex, "rmk"));
};

//-------------------------------------------------------------------------
// 지사/사업소 그리드 클릭
//-------------------------------------------------------------------------
scwin.gr_office_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.bindBranch();
};

scwin.bindBranch = function () {
    var rowIndex = ds_Branch.getRowPosition();
    if (ds_Branch.getCellData(rowIndex, "officeTyp") == "본사")		   //구분 
        rd_branch.setValue("0");
    else if (ds_Branch.getCellData(rowIndex, "officeTyp") == "지사")
        rd_branch.setValue("1");
    else
        rd_branch.setValue("2");

    if (ds_Branch.getCellData(rowIndex, "taxinvcYn") == "가능")  //세금계산서 정보활용 
        cbx_taxinvcYn.setValue("1");
    else
        cbx_taxinvcYn.setValue("");

    acb_branch.setValue(ds_Branch.getCellData(rowIndex, "hdofficeIdx"));
    acb_branch.setDisabled(true);

    ed_ofcNm.setValue(ds_Branch.getCellData(rowIndex, "ofcNm"));
    ed_telNo.setValue(ds_Branch.getCellData(rowIndex, "telNo"));
    ed_faxNo.setValue(ds_Branch.getCellData(rowIndex, "faxNo"));

    acb_prefDistrict1.options.chooseOption = false;
    acb_prefDistrict1.refreshItemset();
    acb_prefDistrict2.options.chooseOption = false;
    acb_prefDistrict2.refreshItemset();

    acb_prefDistrict1.setValue(ds_Branch.getCellData(rowIndex, "prefDistrict1Cd")); //선호권역1
    acb_prefDistrict2.setValue(ds_Branch.getCellData(rowIndex, "prefDistrict2Cd")); //선호권역2
    ed_crnNo.setValue(ds_Branch.getCellData(rowIndex, "crnNo")); //사업자번호
    ed_picNm.setValue(ds_Branch.getCellData(rowIndex, "picNm")); //대표자명
    ed_handphoneNo.setValue(ds_Branch.getCellData(rowIndex, "handphoneNo")); //핸드폰
    ed_picSsn.setValue(ds_Branch.getCellData(rowIndex, "picSsn")); //주민등록번호    
    ed_bizcond.setValue(ds_Branch.getCellData(rowIndex, "bizcond")); //업태
    ed_catBusi.setValue(ds_Branch.getCellData(rowIndex, "catBusi")); //종목
    ed_rmk.setValue(ds_Branch.getCellData(rowIndex, "rmk")); //종목

    udc_coDtlAddr.setValue(ds_Branch.getCellData(rowIndex, "dtlAddr")); //주소
    ed_coZipcode.setValue(ds_Branch.getCellData(rowIndex, "zipcode")); //우편번호
    udc_dtlAddr.setValue(ds_Branch.getCellData(rowIndex, "dmDtlAddr")); //dm주소)
    ed_zipcode.setValue(ds_Branch.getCellData(rowIndex, "dmZipcode")); //dm우편번호

    //계좌정보탭
    ed_bankAcntNo.setValue("");
    ed_dpstr.setValue("");
    ed_accountRmk.setValue("");
    //bankCdVal_combo.Index = 0;
    dma_Branch.set("bankCd", "");

    scwin.BRANCH_IU_FLAG = true;
    scwin.RetrieveAccount();
};

